class LoggingHttpClient extends http.BaseClient {
  LoggingHttpClient(this._inner);

  final http.Client _inner;

  @override
  Future<http.StreamedResponse> send(http.BaseRequest request) async {
    final startedAt = DateTime.now();
    final requestBody = await _extractRequestBody(request);

    AppLogger.info(
      'HTTP REQUEST ${request.method} ${request.url}\n'
      'Headers: ${request.headers}\n'
      'Body: $requestBody',
      tag: 'HTTP',
    );

    try {
      final response = await _inner.send(request);
      final responseBody = await _readStreamedResponseBody(response);

      final duration = DateTime.now().difference(startedAt).inMilliseconds;

      AppLogger.info(
        'HTTP RESPONSE ${request.method} ${request.url}\n'
        'Status: ${response.statusCode}\n'
        'Headers: ${response.headers}\n'
        'Body: $responseBody\n'
        'Duration: ${duration}ms',
        tag: 'HTTP',
      );

      return _rebuildStreamedResponse(response, responseBody);
    } catch (e, st) {
      AppLogger.error(
        'HTTP ERROR ${request.method} ${request.url}',
        tag: 'HTTP',
        error: e,
        stackTrace: st,
      );
      rethrow;
    }
  }

  Future<String> _extractRequestBody(http.BaseRequest request) async {
    if (request is http.Request) {
      return request.body;
    }
    if (request is http.MultipartRequest) {
      final fields = jsonEncode(request.fields);
      final files = request.files
          .map((f) => {
                'field': f.field,
                'filename': f.filename,
                'contentType': f.contentType?.toString(),
                'length': f.length,
              })
          .toList();
      return jsonEncode({
        'fields': jsonDecode(fields),
        'files': files,
      });
    }
    return '<non-readable-body>';
  }

  Future<String> _readStreamedResponseBody(http.StreamedResponse response) async {
    final bytes = await response.stream.toBytes();
    return utf8.decode(bytes, allowMalformed: true);
  }

  http.StreamedResponse _rebuildStreamedResponse(
    http.StreamedResponse original,
    String body,
  ) {
    final bytes = utf8.encode(body);
    return http.StreamedResponse(
      Stream<List<int>>.fromIterable([bytes]),
      original.statusCode,
      contentLength: bytes.length,
      request: original.request,
      headers: original.headers,
      isRedirect: original.isRedirect,
      persistentConnection: original.persistentConnection,
      reasonPhrase: original.reasonPhrase,
    );
  }
}

