      route.settings.name ?? route.runtimeType.toString(),
      data: {
        'action': 'push',
        'previous': previousRoute?.settings.name ?? previousRoute?.runtimeType.toString(),
      },
    );
    super.didPush(route, previousRoute);
  }

  @override
  void didPop(Route route, Route? previousRoute) {
    UserInteractionLogger.screenView(
